+/**
+ * Execute a task-producing function, retrying a rejection up to `n` additional
+ * times. A successful attempt is returned immediately.
+ */
+export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
+  const retries = Math.max(0, Math.floor(n));
+  return new Task((resolve, reject) => {
+    let attempts = 0;
+    const attempt = () => {
+      fn().match({
+        Resolved: resolve,
+        Rejected: (reason) => {
+          if (attempts++ < retries) attempt();
+          else reject(reason);
+        },
+      });
+    };
+    attempt();
+  });
+}
